{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a complex geometric optimization problem (packing/tiling). To solve it, we must decompose it into spatial partitioning, constraint checking, and iterative refinement.",
  "helpers": [
    {
      "label": "spatial_partitioning_check",
      "instructions": "Given a set of target points and target areas, propose a spatial decomposition (e.g., a k-d tree or quadtree) that divides the 10000x10000 grid into regions such that each region contains exactly one target point."
    },
    {
      "label": "rectangle_feasibility_test",
      "instructions": "For a given point (x, y) and a target area A, determine if there exists an axis-aligned rectangle with area A that contains (x, y) and does not overlap with a set of existing rectangles. Check if the rectangle can fit within the 10000x10000 boundary."
    },
    {
      "label": "overlap_and_boundary_validator",
      "instructions": "Given a list of proposed rectangles, perform a sweep-line algorithm or spatial hash check to ensure no two rectangles overlap and all rectangles are contained within the [0, 10000] x [0, 10000] bounds."
    },
    {
      "label": "area_error_calculator",
      "instructions": "Calculate the total satisfaction score by summing the penalty for each advertiser, where penalty is a function of |actual_area - target_area|. Return the total score."
    },
    {
      "label": "greedy_placement_heuristic",
      "instructions": "Implement a greedy strategy: Sort advertisers by target area (descending or ascending) and attempt to place the largest/smallest rectangles first using the feasibility test, adjusting dimensions to minimize area error."
    }
  ],
  "synthesis_brief": "The parent node should use the greedy_placement_heuristic to drive the process. It will use spatial_partitioning_check to organize the points, call rectangle_feasibility_test to propose dimensions for each advertiser, use overlap_and_boundary_validator to ensure the solution is valid, and finally use area_error_calculator to evaluate the quality of the generated set of rectangles."
}
```

